"use strict";(globalThis.webpackChunkpenguinlab=globalThis.webpackChunkpenguinlab||[]).push([[4192],{62821(e,n,t){t.r(n),t.d(n,{assets:()=>l,contentTitle:()=>r,default:()=>d,frontMatter:()=>o,metadata:()=>s,toc:()=>c});const s=JSON.parse('{"id":"notes/linux_kernel_networking/ch12_4","title":"12.4 Power Save Mode","description":"Beyond forwarding packets, an AP has another critical function: acting as a caretaker for \\"sleeping\\" clients by caching their data.","source":"@site/i18n/en/docusaurus-plugin-content-docs/current/notes/linux_kernel_networking/ch12_4.md","sourceDirName":"notes/linux_kernel_networking","slug":"/notes/linux_kernel_networking/ch12_4","permalink":"/PenguinLab/en/notes/linux_kernel_networking/ch12_4","draft":false,"unlisted":false,"editUrl":"https://github.com/Awesome-Embedded-Learning-Studio/PenguinLab/tree/main/../document/notes/linux_kernel_networking/ch12_4.md","tags":[],"version":"current","lastUpdatedBy":"Charliechen114514","lastUpdatedAt":1778326479000,"frontMatter":{},"sidebar":"notesSidebar","previous":{"title":"12.3 Network Topologies","permalink":"/PenguinLab/en/notes/linux_kernel_networking/ch12_3"},"next":{"title":"ch12_5","permalink":"/PenguinLab/en/notes/linux_kernel_networking/ch12_5"}}');var i=t(74934),a=t(31137);const o={},r="12.4 Power Save Mode",l={},c=[{value:"Entering Power Save Mode",id:"entering-power-save-mode",level:3},{value:"Exiting Power Save Mode",id:"exiting-power-save-mode",level:3},{value:"Handling the Multicast/Broadcast Buffer",id:"handling-the-multicastbroadcast-buffer",level:3},{value:"\u26a0\ufe0f Power Save vs. Power Management: Don&#39;t Mix Them Up",id:"\ufe0f-power-save-vs-power-management-dont-mix-them-up",level:3}];function h(e){const n={blockquote:"blockquote",code:"code",em:"em",h1:"h1",h3:"h3",header:"header",hr:"hr",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"124-power-save-mode",children:"12.4 Power Save Mode"})}),"\n",(0,i.jsx)(n.p,{children:'Beyond forwarding packets, an AP has another critical function: acting as a caretaker for "sleeping" clients by caching their data.'}),"\n",(0,i.jsxs)(n.p,{children:["Most wireless clients run on battery power\u2014phones, laptops, and IoT devices. To conserve energy, the wireless NIC can't keep its receiver on all the time; it needs to take naps periodically. But this raises a problem: ",(0,i.jsx)(n.strong,{children:"what happens to the messages sent to you while you're asleep?"})]}),"\n",(0,i.jsx)(n.p,{children:"In wired networks, this isn't an issue because the other end of the cable is always powered. In the wireless world, however, it's a major challenge. In this section, we'll look at how APs and clients in Infrastructure mode solve this problem using an elegant \"push-pull\" mechanism."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h3,{id:"entering-power-save-mode",children:"Entering Power Save Mode"}),"\n",(0,i.jsx)(n.p,{children:"When a client decides to enter power save mode, it can't just quietly doze off\u2014it needs to notify the AP first."}),"\n",(0,i.jsxs)(n.p,{children:["How? Typically by sending a ",(0,i.jsx)(n.strong,{children:"Null Data Packet"}),". The name sounds convoluted, but it's simply a data frame with only an 802.11 header and no payload. The real purpose of this packet isn't to carry data, but to flip a flag in the Frame Control field of the header: the ",(0,i.jsx)(n.strong,{children:"PM (Power Management) bit"}),"."]}),"\n",(0,i.jsx)(n.p,{children:"Once this PM bit is set to 1, the AP understands: this client is going to sleep."}),"\n",(0,i.jsxs)(n.p,{children:["You can think of this as hanging a ",(0,i.jsx)(n.strong,{children:'"Do Not Disturb"'})," sign on your door. You put up the sign (send the Null Packet), and when the waiter (AP) passes by and sees it, they stop knocking on your door to answer calls."]}),"\n",(0,i.jsxs)(n.p,{children:['But the "hanging a sign" analogy falls short in one respect: a real waiter might just not knock, but the caller might hang up. In 802.11, however, the AP not only avoids disturbing you, but also ',(0,i.jsx)(n.strong,{children:"records and stores all incoming calls (packets) for you"})," (caching)."]}),"\n",(0,i.jsxs)(n.p,{children:["Upon receiving a packet with PM=1, the AP immediately activates a caching mechanism. Inside the kernel (specifically in the mac80211 subsystem), it maintains a queue for each associated station called ",(0,i.jsx)(n.strong,{children:"ps_tx_buf"}),"."]}),"\n",(0,i.jsxs)(n.p,{children:["This ",(0,i.jsx)(n.code,{children:"ps_tx_buf"})," is a linked list structure dedicated to storing unicast packets destined for that station."]}),"\n",(0,i.jsxs)(n.p,{children:["However, memory is finite. mac80211 sets a hard limit on the ",(0,i.jsx)(n.code,{children:"ps_tx_buf"})," for each station: ",(0,i.jsx)(n.strong,{children:"128 packets"})," (",(0,i.jsx)(n.code,{children:"STA_MAX_TX_BUFFER"}),")."]}),"\n",(0,i.jsxs)(n.p,{children:["\u26a0\ufe0f ",(0,i.jsx)(n.strong,{children:"Warning"})]}),"\n",(0,i.jsx)(n.p,{children:"This limit is strict. If a client sleeps for too long while the sender is aggressive, these 128 slots will fill up quickly."}),"\n",(0,i.jsxs)(n.p,{children:["What happens when it's full? The AP won't crash; it starts \"throwing things out.\" It follows the ",(0,i.jsx)(n.strong,{children:"FIFO (First In, First Out)"})," principle\u2014dropping the oldest packets to make room for new ones. This means if your phone goes into a deep sleep in power save mode, you might find that the earliest messages are missing when you wake up, and they are gone for good."]}),"\n",(0,i.jsxs)(n.p,{children:["Beyond unicast packets, there's an even trickier customer: ",(0,i.jsx)(n.strong,{children:"multicast/broadcast packets"}),"."]}),"\n",(0,i.jsxs)(n.p,{children:["Why are they tricky? Because by definition in 802.11, a broadcast packet must be delivered to ",(0,i.jsx)(n.strong,{children:"everyone"})," in the BSS. As long as even one person is sleeping, the broadcast packet cannot be transmitted\u2014because the sleeping client wouldn't receive it anyway."]}),"\n",(0,i.jsxs)(n.p,{children:["To solve this, the AP maintains a global, shared buffer: ",(0,i.jsx)(n.strong,{children:"bc_buf"}),"."]}),"\n",(0,i.jsxs)(n.p,{children:["As long as ",(0,i.jsx)(n.strong,{children:"at least one"})," station in the BSS is in sleep mode, the AP will stuff all multicast and broadcast packets into this ",(0,i.jsx)(n.code,{children:"bc_buf"}),". This buffer also has a limit, which is likewise ",(0,i.jsx)(n.strong,{children:"128 packets"})," (",(0,i.jsx)(n.code,{children:"AP_MAX_BC_BUFFER"}),")."]}),"\n",(0,i.jsx)(n.p,{children:"Now we can refine our analogy: the AP is like a front desk. When you're asleep (PM=1), the front desk stuffs your personal mail into your private mailbox, and locks the mass-mailed flyers in a drawer\u2014as long as even one person in the room is sleeping, the flyers aren't distributed; they wait until everyone is awake."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h3,{id:"exiting-power-save-mode",children:"Exiting Power Save Mode"}),"\n",(0,i.jsx)(n.p,{children:"Clients sleep to save power, not to enter a coma. They need to wake up and do work. How do they know when to wake up? Usually via a timer."}),"\n",(0,i.jsx)(n.p,{children:"What's the first thing to do upon waking up? Listen to the broadcast."}),"\n",(0,i.jsxs)(n.p,{children:["The AP ",(0,i.jsx)(n.strong,{children:"periodically"})," sends a special management frame called a ",(0,i.jsx)(n.strong,{children:"Beacon"}),". This frequency is quite high, typically 10 per second (",(0,i.jsx)(n.code,{children:"100ms"})," interval). You can think of it as the AP's heartbeat, or a clock chiming on the hour."]}),"\n",(0,i.jsxs)(n.p,{children:["Beacon frames don't just carry timing synchronization; they also carry a critical Information Element called the ",(0,i.jsx)(n.strong,{children:"TIM (Traffic Indication Map)"}),"."]}),"\n",(0,i.jsx)(n.p,{children:"This is a very clever bitmap design."}),"\n",(0,i.jsxs)(n.p,{children:["Remember the AID we mentioned earlier? Every associated station has an ID from 1 to 2007. The TIM is an array containing 2008 bits (corresponding to AID 0-2007). If the AP finds packets sitting in your ",(0,i.jsx)(n.code,{children:"ps_tx_buf"}),", it sets ",(0,i.jsx)(n.strong,{children:"your corresponding bit in the TIM to 1"}),"."]}),"\n",(0,i.jsx)(n.p,{children:"After waking up, the client catches a Beacon and starts checking the TIM."}),"\n",(0,i.jsxs)(n.p,{children:["This check is implemented in the kernel via the ",(0,i.jsx)(n.code,{children:"ieee80211_check_tim()"})," method (defined in ",(0,i.jsx)(n.code,{children:"include/linux/ieee80211.h"}),"). It doesn't need to read the entire TIM; it only needs to calculate whether the bit corresponding to its AID is 1."]}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsx)(n.li,{children:"If it's 0: Great, nobody is looking for me, go back to sleep."}),"\n",(0,i.jsx)(n.li,{children:"If it's 1: Wake up, there's work to do."}),"\n"]}),"\n",(0,i.jsx)(n.p,{children:'Once a client sees its bit set to 1, it knows the AP is holding packages for it. At this point, it needs to actively "pick up the goods."'}),"\n",(0,i.jsxs)(n.p,{children:["How? By sending a ",(0,i.jsx)(n.strong,{children:"PS-Poll (Power Save Poll)"})," control frame."]}),"\n",(0,i.jsx)(n.p,{children:'You can think of PS-Poll as you slapping the front desk: "Hey, where\'s my mail?".'}),"\n",(0,i.jsxs)(n.p,{children:["Upon receiving the PS-Poll, the AP pulls a packet from the ",(0,i.jsx)(n.code,{children:"ps_tx_buf"})," and sends it to you. Here's the subtle part: ",(0,i.jsxs)(n.strong,{children:["the AP sets a flag called ",(0,i.jsx)(n.code,{children:"IEEE80211_FCTL_MOREDATA"})," in the Frame Control field of every packet it sends out"]}),"."]}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsx)(n.li,{children:'If this bit is 1: It means "there\'s more, keep polling."'}),"\n",(0,i.jsx)(n.li,{children:'If this bit is 0: It means "this is the last one, take it and go back to sleep."'}),"\n"]}),"\n",(0,i.jsxs)(n.p,{children:["The client relies on this bit to decide whether to send another PS-Poll. Once it receives a packet with ",(0,i.jsx)(n.code,{children:"MOREDATA=0"}),", it knows the inventory is empty and will typically re-enter sleep mode (of course, the standard doesn't force you to sleep; you can stay awake, but your battery will drain fast)."]}),"\n",(0,i.jsxs)(n.blockquote,{children:["\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:'Back to the "front desk" analogy'}),':\nThe TIM is like a scrolling screen in the lobby displaying "Package for Room 101." You wake up, glance at the screen, see your name, and go tap your card at the counter.\nThe front desk hands you the first package and casually says, "There\'s one more." You take it and tap your card again, until the front desk hands you the last one without saying anything\u2014then you know you\'re done and can go back to your room to sleep.']}),"\n"]}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h3,{id:"handling-the-multicastbroadcast-buffer",children:"Handling the Multicast/Broadcast Buffer"}),"\n",(0,i.jsx)(n.p,{children:"The logic for unicast packets is straightforward: cache for whoever is sleeping. But the logic for multicast/broadcast packets is slightly more complex."}),"\n",(0,i.jsxs)(n.p,{children:["Per the standard, the AID for multicast/broadcast is defined as ",(0,i.jsx)(n.strong,{children:"0"}),"."]}),"\n",(0,i.jsx)(n.p,{children:"So, when the AP has a broadcast packet to send and someone in the room is sleeping, it sets bit 0 of the TIM (TIM[0]) to 1. But that alone isn't enough."}),"\n",(0,i.jsxs)(n.p,{children:["Broadcast packets are noisy and power-hungry. If a client had to process broadcast packets every time it woke up, it would be miserable. Moreover, many devices aren't very interested in broadcast packets. Therefore, 802.11 introduced a concept called ",(0,i.jsx)(n.strong,{children:"DTIM (Delivery TIM)"}),"."]}),"\n",(0,i.jsxs)(n.p,{children:["DTIM is a special type of TIM that doesn't appear in every Beacon, but rather every few Beacons. This interval is called the ",(0,i.jsx)(n.strong,{children:"DTIM Period"}),", typically configured to 3 or 5 (i.e., once every 300ms - 500ms)."]}),"\n",(0,i.jsxs)(n.p,{children:["Only after a Beacon carrying a DTIM does the AP dump all the backlogged broadcast/multicast packets from the ",(0,i.jsx)(n.code,{children:"bc_buf"}),". This means clients can ignore the TIM[0] in normal Beacons and only wake up during the DTIM cycle to handle broadcast packets, drastically saving power."]}),"\n",(0,i.jsxs)(n.p,{children:["In kernel code, we need to call the ",(0,i.jsx)(n.code,{children:"ieee80211_get_buffered_bc()"}),' method to "extract" these packets from the ',(0,i.jsx)(n.code,{children:"bc_buf"}),"."]}),"\n",(0,i.jsx)(n.p,{children:"Let's look at a diagram to clarify the positions of these buffers."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"(Figure 12-3 here: Diagram of buffered packets in an AP, showing the sta_info linked list, their respective ps_tx_buf, and the shared bc_buf)"})}),"\n",(0,i.jsxs)(n.p,{children:["In the mac80211 implementation, the AP is abstracted as a ",(0,i.jsx)(n.code,{children:"ieee80211_if_ap"})," object. This object has a member called ",(0,i.jsx)(n.code,{children:"ps"})," (an instance of the ",(0,i.jsx)(n.code,{children:"ps_data"})," structure). The shared ",(0,i.jsx)(n.code,{children:"bc_buf"})," mentioned earlier lives right inside the ",(0,i.jsx)(n.code,{children:"ps"})," structure."]}),"\n",(0,i.jsx)(n.p,{children:'The next diagram shows the process of a client frantically "picking up goods" using PS-Poll.'}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"(Figure 12-4 here: Flowchart of a client sending PSPOLL packets to retrieve data packets from the AP's ps_tx_buf)"})}),"\n",(0,i.jsxs)(n.p,{children:["Notice the data flow in the diagram: every packet sent by the AP, except the last one, ",(0,i.jsxs)(n.strong,{children:["carries the ",(0,i.jsx)(n.code,{children:"MOREDATA"})," flag"]}),". This is the signal that keeps the client hungry for more. Once this signal disappears, the interaction ends."]}),"\n",(0,i.jsx)(n.p,{children:"(For simplicity, the ACK flow isn't drawn in the diagram, but in reality every data packet requires an ACK acknowledgment. Don't forget this when implementing the driver.)"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h3,{id:"\ufe0f-power-save-vs-power-management-dont-mix-them-up",children:"\u26a0\ufe0f Power Save vs. Power Management: Don't Mix Them Up"}),"\n",(0,i.jsx)(n.p,{children:"There's a terminology trap here that trips up many beginners (and even veterans)."}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Power Management"})," and ",(0,i.jsx)(n.strong,{children:"Power Save Mode"})," are two entirely different things."]}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Power Save Mode"}),": This is what we discussed above. The client sleeps for a few milliseconds, and the AP helps cache packets. This is a ",(0,i.jsx)(n.strong,{children:"protocol-level task within 802.11"})," that happens during normal operation."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Power Management"}),": This is a system-level task. For example, when you close your laptop lid (Suspend to RAM) or click hibernate (Hibernate). At this point, not only is the NIC down, but the entire CPU has nearly stopped. This is handled by the kernel's PM framework, in ",(0,i.jsx)(n.code,{children:"net/mac80211/pm.c"}),", where it corresponds to the ",(0,i.jsx)(n.code,{children:"resume"}),"/",(0,i.jsx)(n.code,{children:"suspend"})," callbacks in the driver."]}),"\n"]}),"\n",(0,i.jsxs)(n.p,{children:["Don't confuse the two. If you find yourself trying to handle the TIM bitmap inside the ",(0,i.jsx)(n.code,{children:"suspend"})," callback when writing a driver, you've walked into the wrong room."]}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsxs)(n.p,{children:["In this section, we really only talked about one thing: ",(0,i.jsx)(n.strong,{children:"trust"}),"."]}),"\n",(0,i.jsx)(n.p,{children:"The client trusts that the AP will safeguard its data packets while it sleeps; the AP trusts that the client will proactively pick them up when it wakes. To maintain this trust, they need seemingly tedious handshake signals like TIM, PS-Poll, and Null Data."}),"\n",(0,i.jsxs)(n.p,{children:["In the next section, we'll zoom out and look at the behind-the-scenes hero that supports all connections, scanning, and authentication\u2014",(0,i.jsx)(n.strong,{children:"MLME (MAC Layer Management Entity)"}),". Without it, wireless networks would just be a disorganized mess."]})]})}function d(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(h,{...e})}):h(e)}},31137(e,n,t){t.d(n,{R:()=>o,x:()=>r});var s=t(2086);const i={},a=s.createContext(i);function o(e){const n=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:o(e.components),s.createElement(a.Provider,{value:n},e.children)}}}]);